// 数据清洗：标准化新闻条目
const items = $input.all();
const cleaned = items.map((item, index) => {
  const data = item.json;

  // 提取标题
  const title = data.title || data.name || data.headline || '';

  // 提取摘要
  const summary = data.description || data.summary || data.contentSnippet || '';

  // 提取链接
  const sourceUrl = data.link || data.url || data.guid || '';

  // 提取发布时间
  const publishedAt = data.pubDate || data.published || data.date || new Date().toISOString();

  // 提取来源
  const source = data['dc:creator'] || data.author || data.source || '未知来源';

  // 智能分类
  const content = (title + ' ' + summary).toLowerCase();
  let category = 'trade';
  if (content.includes('政策') || content.includes('法') || content.includes('規制') || content.includes('通知')) category = 'policy';
  else if (content.includes('博览') || content.includes('展会') || content.includes('フェア') || content.includes('見本市')) category = 'event';
  else if (content.includes('市場') || content.includes('价格') || content.includes('price')) category = 'market';
  else if (content.includes('産業') || content.includes('行业') || content.includes('industry')) category = 'industry';

  // 判断国家
  let country = 'bilateral';
  if (content.includes('中国') && !content.includes('日本')) country = 'cn';
  else if (content.includes('日本') && !content.includes('中国')) country = 'jp';

  return {
    json: {
      id: `${Date.now()}-${index}`,
      title: title.trim(),
      summary: summary.trim().slice(0, 500),
      source: source.trim(),
      sourceUrl: sourceUrl,
      category,
      country,
      tags: [],
      publishedAt: new Date(publishedAt).toISOString(),
      collectedAt: new Date().toISOString(),
      collectionSource: data.collectionSource || 'rss'
    }
  };
});

return cleaned;

// AI 生成摘要和标签
const items = $input.all();
const results = [];

// 模拟 AI 增强（实际使用 OpenAI / Claude API）
for (const item of items) {
  const data = item.json;
  const title = data.title || '';
  const summary = data.summary || '';
  const content = title + ' ' + summary;

  // 简单关键词提取作为标签
  const keywords = [];
  const keywordMap = {
    '投资': '投资',
    '新能源': '新能源',
    '半导体': '半导体',
    '汽车': '汽车',
    '医药': '医药',
    '农业': '农业',
    '贸易': '贸易',
    '电商': '电商',
    '机器人': '机器人',
    'AI': 'AI',
    '精密': '精密制造',
    '电池': '新能源',
    '制造': '制造业',
    '合作': '合作',
    '关税': '关税'
  };

  for (const [key, tag] of Object.entries(keywordMap)) {
    if (content.includes(key)) keywords.push(tag);
  }

  // 去重
  const uniqueTags = [...new Set(keywords)].slice(0, 5);

  // 生成摘要（实际调用 AI）
  const aiSummary = summary.length > 100 
    ? summary 
    : summary + ' — 本资讯由中日经贸通自动采集整理。';

  results.push({
    json: {
      ...data,
      tags: uniqueTags,
      summary: aiSummary,
      isFeatured: data.category === 'trade' && uniqueTags.length >= 2
    }
  });
}

return results;

// 触发 Vercel Webhook 重新验证页面
const data = $('AI 摘要生成 & 标签提取').all();

// 返回 webhook 调用
return [{
  json: {
    webhookUrl: process.env.VERCEL_REVALIDATE_HOOK,
    tags: data.flatMap(d => d.json.tags || []),
    count: data.length
  }
}];
